import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class PathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String baseDir = "/var/www/html/data/";

        // Validate and sanitize user input to prevent path traversal
        String sanitizedInput = Paths.get(userInput).normalize().toString();

        // Check if the normalized input is safe
        if (!sanitizedInput.startsWith("..")) {
            String fullPath = baseDir + sanitizedInput;

            try {
                File file = new File(fullPath);
                FileInputStream fis = new FileInputStream(file);

                int content;
                while ((content = fis.read()) != -1) {
                    System.out.print((char) content);
                }

                fis.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        } else {
            System.out.println("Invalid file path.");
        }
    }
}

